package com.example.controller

import com.example.db.dao.CategoryDao
import com.example.db.dao.DepartmentDao
import com.example.model.Category
import com.example.model.CategoryRequest
import com.example.model.Department
import com.example.model.DepartmentRequest
import com.example.security.AuthorizationUtil
import com.example.model.UserRole
import io.ktor.http.HttpStatusCode
import io.ktor.server.application.call
import io.ktor.server.request.receive
import io.ktor.server.response.respond
import io.ktor.server.routing.Route
import io.ktor.server.routing.delete
import io.ktor.server.routing.get
import io.ktor.server.routing.post
import io.ktor.server.routing.put
import io.ktor.server.routing.route

class AdminController(
    private val categoryDao: CategoryDao,
    private val departmentDao: DepartmentDao
) {
    fun register(routing: Route) {
        routing.route("/api/admin") {
            // Categories endpoints
            route("/categories") {
                // GET all categories (Public)
                get {
                    try {
                        val categories = categoryDao.findAll()
                        call.respond(categories)
                    } catch (e: Exception) {
                        call.respond(HttpStatusCode.InternalServerError,
                            mapOf("error" to e.message.orEmpty()))
                    }
                }

                // POST create category (Admin only)
                post {
                    try {
                        if (!AuthorizationUtil.requireAdmin(call)) return@post

                        val request = call.receive<CategoryRequest>()
                        if (request.name.isBlank()) {
                            return@post call.respond(HttpStatusCode.BadRequest,
                                mapOf("error" to "Category name cannot be empty"))
                        }

                        // Check if category already exists
                        val existing = categoryDao.findByName(request.name)
                        if (existing != null) {
                            return@post call.respond(HttpStatusCode.Conflict,
                                mapOf("error" to "Category already exists"))
                        }

                        val category = Category(id = 0, name = request.name)
                        val created = categoryDao.create(category)
                        call.respond(HttpStatusCode.Created, created)
                    } catch (e: Exception) {
                        call.respond(HttpStatusCode.InternalServerError,
                            mapOf("error" to e.message.orEmpty()))
                    }
                }

                // PUT update category (Admin only)
                put("/{id}") {
                    try {
                        if (!AuthorizationUtil.requireAdmin(call)) return@put

                        val categoryId = call.parameters["id"]?.toLongOrNull()
                            ?: return@put call.respond(HttpStatusCode.BadRequest,
                                mapOf("error" to "Invalid category ID"))

                        val request = call.receive<CategoryRequest>()
                        if (request.name.isBlank()) {
                            return@put call.respond(HttpStatusCode.BadRequest,
                                mapOf("error" to "Category name cannot be empty"))
                        }

                        val category = Category(id = categoryId, name = request.name)
                        val updated = categoryDao.update(categoryId, category)
                        if (updated != null) {
                            call.respond(updated)
                        } else {
                            call.respond(HttpStatusCode.NotFound,
                                mapOf("error" to "Category not found"))
                        }
                    } catch (e: Exception) {
                        call.respond(HttpStatusCode.InternalServerError,
                            mapOf("error" to e.message.orEmpty()))
                    }
                }

                // DELETE category (Admin only)
                delete("/{id}") {
                    try {
                        if (!AuthorizationUtil.requireAdmin(call)) return@delete

                        val categoryId = call.parameters["id"]?.toLongOrNull()
                            ?: return@delete call.respond(HttpStatusCode.BadRequest,
                                mapOf("error" to "Invalid category ID"))

                        if (categoryDao.delete(categoryId)) {
                            call.respond(HttpStatusCode.NoContent)
                        } else {
                            call.respond(HttpStatusCode.NotFound,
                                mapOf("error" to "Category not found"))
                        }
                    } catch (e: Exception) {
                        call.respond(HttpStatusCode.InternalServerError,
                            mapOf("error" to e.message.orEmpty()))
                    }
                }
            }

            // Departments endpoints
            route("/departments") {
                // GET all departments (Public)
                get {
                    try {
                        val departments = departmentDao.findAll()
                        call.respond(departments)
                    } catch (e: Exception) {
                        call.respond(HttpStatusCode.InternalServerError,
                            mapOf("error" to e.message.orEmpty()))
                    }
                }

                // POST create department (Admin only)
                post {
                    try {
                        if (!AuthorizationUtil.requireAdmin(call)) return@post

                        val request = call.receive<DepartmentRequest>()
                        if (request.name.isBlank()) {
                            return@post call.respond(HttpStatusCode.BadRequest,
                                mapOf("error" to "Department name cannot be empty"))
                        }

                        // Check if department already exists
                        val existing = departmentDao.findByName(request.name)
                        if (existing != null) {
                            return@post call.respond(HttpStatusCode.Conflict,
                                mapOf("error" to "Department already exists"))
                        }

                        val department = Department(id = 0, name = request.name)
                        val created = departmentDao.create(department)
                        call.respond(HttpStatusCode.Created, created)
                    } catch (e: Exception) {
                        call.respond(HttpStatusCode.InternalServerError,
                            mapOf("error" to e.message.orEmpty()))
                    }
                }

                // PUT update department (Admin only)
                put("/{id}") {
                    try {
                        if (!AuthorizationUtil.requireAdmin(call)) return@put

                        val departmentId = call.parameters["id"]?.toLongOrNull()
                            ?: return@put call.respond(HttpStatusCode.BadRequest,
                                mapOf("error" to "Invalid department ID"))

                        val request = call.receive<DepartmentRequest>()
                        if (request.name.isBlank()) {
                            return@put call.respond(HttpStatusCode.BadRequest,
                                mapOf("error" to "Department name cannot be empty"))
                        }

                        val department = Department(id = departmentId, name = request.name)
                        val updated = departmentDao.update(departmentId, department)
                        if (updated != null) {
                            call.respond(updated)
                        } else {
                            call.respond(HttpStatusCode.NotFound,
                                mapOf("error" to "Department not found"))
                        }
                    } catch (e: Exception) {
                        call.respond(HttpStatusCode.InternalServerError,
                            mapOf("error" to e.message.orEmpty()))
                    }
                }

                // DELETE department (Admin only)
                delete("/{id}") {
                    try {
                        if (!AuthorizationUtil.requireAdmin(call)) return@delete

                        val departmentId = call.parameters["id"]?.toLongOrNull()
                            ?: return@delete call.respond(HttpStatusCode.BadRequest,
                                mapOf("error" to "Invalid department ID"))

                        if (departmentDao.delete(departmentId)) {
                            call.respond(HttpStatusCode.NoContent)
                        } else {
                            call.respond(HttpStatusCode.NotFound,
                                mapOf("error" to "Department not found"))
                        }
                    } catch (e: Exception) {
                        call.respond(HttpStatusCode.InternalServerError,
                            mapOf("error" to e.message.orEmpty()))
                    }
                }
            }
        }
    }
}

package com.example.controller

import com.example.model.UserLoginRequest
import com.example.model.UserRegisterRequest
import com.example.service.AuthService
import io.ktor.server.application.call
import io.ktor.server.auth.principal
import io.ktor.server.request.receive
import io.ktor.server.response.respond
import io.ktor.server.routing.Route
import io.ktor.server.routing.post
import io.ktor.server.routing.get
import io.ktor.server.routing.route
import io.ktor.server.auth.jwt.JWTPrincipal
import com.example.model.JwtClaims

class AuthController(private val authService: AuthService) {
    fun register(routing: Route) {
        routing.route("/auth") {
            post("/register") {
                try {
                    val request = call.receive<UserRegisterRequest>()
                    val response = authService.register(request)
                    call.respond(response)
                } catch (e: IllegalArgumentException) {
                    call.respond(mapOf("error" to e.message.orEmpty()))
                } catch (e: Exception) {
                    call.respond(mapOf("error" to "Registration failed: ${e.message}"))
                }
            }

            post("/login") {
                try {
                    val request = call.receive<UserLoginRequest>()
                    val response = authService.login(request)
                    call.respond(response)
                } catch (e: IllegalArgumentException) {
                    call.respond(mapOf("error" to e.message.orEmpty()))
                } catch (e: Exception) {
                    call.respond(mapOf("error" to "Login failed: ${e.message}"))
                }
            }

            get("/me") {
                try {
                    val principal = call.principal<JWTPrincipal>()
                    if (principal != null) {
                        val userIdStr = principal.subject
                        if (!userIdStr.isNullOrBlank()) {
                            val userId = userIdStr.toLong()
                            val userResponse = authService.getUserById(userId)
                            if (userResponse != null) {
                                call.respond(userResponse)
                            } else {
                                call.respond(mapOf("error" to "User not found"))
                            }
                        } else {
                            call.respond(mapOf("error" to "Invalid token"))
                        }
                    } else {
                        call.respond(mapOf("error" to "Unauthorized"))
                    }
                } catch (e: Exception) {
                    call.respond(mapOf("error" to "Failed to fetch user: ${e.message}"))
                }
            }
        }
    }
}

package com.example.controller

import com.example.model.RegistrationRequest
import com.example.service.RegistrationService
import com.example.security.AuthorizationUtil
import io.ktor.http.HttpStatusCode
import io.ktor.server.application.call
import io.ktor.server.request.receive
import io.ktor.server.response.respond
import io.ktor.server.routing.Route
import io.ktor.server.routing.delete
import io.ktor.server.routing.get
import io.ktor.server.routing.post
import io.ktor.server.routing.put
import io.ktor.server.routing.route

class RegistrationController(private val registrationService: RegistrationService) {
    fun register(routing: Route) {
        routing.route("/api/registrations") {
            // Get my registrations (Student)
            get {
                try {
                    val userId = AuthorizationUtil.getUserIdFromPrincipal(call)
                        ?: return@get call.respond(HttpStatusCode.Unauthorized,
                            mapOf("error" to "Unauthorized"))

                    val registrations = registrationService.getStudentRegistrations(userId)
                    call.respond(registrations)
                } catch (e: Exception) {
                    call.respond(HttpStatusCode.InternalServerError,
                        mapOf("error" to e.message.orEmpty()))
                }
            }

            // Register for event (Student)
            post {
                try {
                    val userId = AuthorizationUtil.getUserIdFromPrincipal(call)
                        ?: return@post call.respond(HttpStatusCode.Unauthorized,
                            mapOf("error" to "Unauthorized"))

                    val request = call.receive<RegistrationRequest>()

                    val registration = registrationService.registerStudent(userId, request.eventId)
                    call.respond(HttpStatusCode.Created, registration)
                } catch (e: IllegalArgumentException) {
                    call.respond(HttpStatusCode.BadRequest,
                        mapOf("error" to e.message.orEmpty()))
                } catch (e: Exception) {
                    call.respond(HttpStatusCode.InternalServerError,
                        mapOf("error" to e.message.orEmpty()))
                }
            }

            // Cancel registration (Student)
            delete("/{registrationId}") {
                try {
                    val userId = AuthorizationUtil.getUserIdFromPrincipal(call)
                        ?: return@delete call.respond(HttpStatusCode.Unauthorized,
                            mapOf("error" to "Unauthorized"))

                    val registrationId = call.parameters["registrationId"]?.toLongOrNull()
                        ?: return@delete call.respond(HttpStatusCode.BadRequest,
                            mapOf("error" to "Invalid registration ID"))

                    if (registrationService.cancelRegistration(userId, registrationId)) {
                        call.respond(HttpStatusCode.NoContent)
                    } else {
                        call.respond(HttpStatusCode.NotFound,
                            mapOf("error" to "Registration not found"))
                    }
                } catch (e: IllegalArgumentException) {
                    call.respond(HttpStatusCode.Forbidden,
                        mapOf("error" to e.message.orEmpty()))
                } catch (e: Exception) {
                    call.respond(HttpStatusCode.InternalServerError,
                        mapOf("error" to e.message.orEmpty()))
                }
            }

            // Get event participants (Organizer/Admin)
            get("/event/{eventId}") {
                try {
                    if (!AuthorizationUtil.requireRole(call, com.example.model.UserRole.ORGANIZER, com.example.model.UserRole.ADMIN)) {
                        return@get
                    }

                    val eventId = call.parameters["eventId"]?.toLongOrNull()
                        ?: return@get call.respond(HttpStatusCode.BadRequest,
                            mapOf("error" to "Invalid event ID"))

                    val participants = registrationService.getEventParticipants(eventId)
                    call.respond(participants)
                } catch (e: Exception) {
                    call.respond(HttpStatusCode.InternalServerError,
                        mapOf("error" to e.message.orEmpty()))
                }
            }

            // Update registration status (Admin/Organizer)
            put("/{registrationId}/status") {
                try {
                    val userRole = AuthorizationUtil.getUserRoleFromPrincipal(call)
                        ?: return@put call.respond(HttpStatusCode.Unauthorized,
                            mapOf("error" to "Unauthorized"))

                    val registrationId = call.parameters["registrationId"]?.toLongOrNull()
                        ?: return@put call.respond(HttpStatusCode.BadRequest,
                            mapOf("error" to "Invalid registration ID"))

                    val statusUpdate = call.receive<Map<String, String>>()
                    val status = statusUpdate["status"]
                        ?: return@put call.respond(HttpStatusCode.BadRequest,
                            mapOf("error" to "Status field is required"))

                    registrationService.updateRegistrationStatus(registrationId, status, userRole.name)
                    call.respond(HttpStatusCode.NoContent)
                } catch (e: IllegalArgumentException) {
                    call.respond(HttpStatusCode.BadRequest,
                        mapOf("error" to e.message.orEmpty()))
                } catch (e: Exception) {
                    call.respond(HttpStatusCode.InternalServerError,
                        mapOf("error" to e.message.orEmpty()))
                }
            }
        }
    }
}

package com.example.controller

import com.example.model.UserRole
import com.example.service.AuthService
import com.example.security.AuthorizationUtil
import io.ktor.http.HttpStatusCode
import io.ktor.server.application.call
import io.ktor.server.response.respond
import io.ktor.server.routing.Route
import io.ktor.server.routing.get
import io.ktor.server.routing.route

class UserController(private val authService: AuthService) {
    fun register(routing: Route) {
        routing.route("/api/users") {
            // Get all users (Admin only)
            get {
                if (!AuthorizationUtil.requireAdmin(call)) return@get

                try {
                    val students = authService.getUsersByRole(UserRole.STUDENT)
                    val organizers = authService.getUsersByRole(UserRole.ORGANIZER)
                    val admins = authService.getUsersByRole(UserRole.ADMIN)

                    call.respond(mapOf(
                        "students" to students,
                        "organizers" to organizers,
                        "admins" to admins
                    ))
                } catch (e: Exception) {
                    call.respond(HttpStatusCode.InternalServerError, 
                        mapOf("error" to "Failed to fetch users: ${e.message}"))
                }
            }

            // Get users by role (Admin only)
            get("/{role}") {
                if (!AuthorizationUtil.requireAdmin(call)) return@get

                try {
                    val roleStr = call.parameters["role"]?.uppercase() ?: return@get
                    val role = try {
                        UserRole.valueOf(roleStr)
                    } catch (e: IllegalArgumentException) {
                        return@get call.respond(HttpStatusCode.BadRequest, 
                            mapOf("error" to "Invalid role: $roleStr"))
                    }

                    val users = authService.getUsersByRole(role)
                    call.respond(users)
                } catch (e: Exception) {
                    call.respond(HttpStatusCode.InternalServerError, 
                        mapOf("error" to "Failed to fetch users: ${e.message}"))
                }
            }
        }
    }
}

package com.example.db.dao
import com.example.model.Category
interface CategoryDao { fun findAll(): List<Category> fun findById(id: Long): Category? fun create(category: Category): Category fun update(id: Long, category: Category): Category? fun delete(id: Long): Boolean fun findByName(name: String): Category? }

package com.example.db.dao
import com.example.model.Department
interface DepartmentDao { fun findAll(): List<Department> fun findById(id: Long): Department? fun create(department: Department): Department fun update(id: Long, department: Department): Department? fun delete(id: Long): Boolean fun findByName(name: String): Department? }

package com.example.db.dao

import com.example.model.Category
import javax.sql.DataSource

class JdbcCategoryDao(private val dataSource: DataSource) : CategoryDao {
    override fun findAll(): List<Category> = dataSource.connection.use { connection ->
        connection.prepareStatement(
            "SELECT id, name FROM categories ORDER BY id"
        ).use { statement ->
            statement.executeQuery().use { rs ->
                buildList {
                    while (rs.next()) {
                        add(rs.toCategory())
                    }
                }
            }
        }
    }

    override fun findById(id: Long): Category? = dataSource.connection.use { connection ->
        connection.prepareStatement(
            "SELECT id, name FROM categories WHERE id = ?"
        ).use { statement ->
            statement.setLong(1, id)
            statement.executeQuery().use { rs ->
                if (rs.next()) rs.toCategory() else null
            }
        }
    }

    override fun create(category: Category): Category = dataSource.connection.use { connection ->
        connection.prepareStatement(
            "INSERT INTO categories(name) VALUES (?) RETURNING id, name"
        ).use { statement ->
            statement.setString(1, category.name)
            statement.executeQuery().use { rs ->
                rs.next()
                rs.toCategory()
            }
        }
    }

    override fun update(id: Long, category: Category): Category? = dataSource.connection.use { connection ->
        connection.prepareStatement(
            "UPDATE categories SET name = ? WHERE id = ? RETURNING id, name"
        ).use { statement ->
            statement.setString(1, category.name)
            statement.setLong(2, id)
            statement.executeQuery().use { rs ->
                if (rs.next()) rs.toCategory() else null
            }
        }
    }

    override fun delete(id: Long): Boolean = dataSource.connection.use { connection ->
        connection.prepareStatement("DELETE FROM categories WHERE id = ?").use { statement ->
            statement.setLong(1, id)
            statement.executeUpdate() > 0
        }
    }

    override fun findByName(name: String): Category? = dataSource.connection.use { connection ->
        connection.prepareStatement(
            "SELECT id, name FROM categories WHERE LOWER(name) = LOWER(?)"
        ).use { statement ->
            statement.setString(1, name)
            statement.executeQuery().use { rs ->
                if (rs.next()) rs.toCategory() else null
            }
        }
    }

    private fun java.sql.ResultSet.toCategory(): Category = Category(
        id = getLong("id"),
        name = getString("name")
    )
}

