package com.example.security

import com.example.model.UserRole
import io.ktor.http.HttpStatusCode
import io.ktor.server.application.ApplicationCall
import io.ktor.server.auth.jwt.JWTPrincipal
import io.ktor.server.auth.principal
import io.ktor.server.response.respond

/**
 * Authorization utility for role-based access control
 */
object AuthorizationUtil {

    /**
     * Get user ID from JWT principal
     */
    suspend fun getUserIdFromPrincipal(call: ApplicationCall): Long? {
        val principal = call.principal<JWTPrincipal>()
        return principal?.subject?.toLongOrNull()
    }

    /**
     * Get user role from JWT principal
     */
    suspend fun getUserRoleFromPrincipal(call: ApplicationCall): UserRole? {
        val principal = call.principal<JWTPrincipal>()
        val role = principal?.payload?.getClaim("role")?.asString()
        return role?.let { UserRole.valueOf(it) }
    }

    /**
     * Check if user has required role(s)
     * Returns true if user has any of the provided roles
     */
    suspend fun hasRole(call: ApplicationCall, vararg requiredRoles: UserRole): Boolean {
        val userRole = getUserRoleFromPrincipal(call) ?: return false
        return userRole in requiredRoles
    }

    /**
     * Require specific role(s), respond with Forbidden if not authorized
     */
    suspend fun requireRole(call: ApplicationCall, vararg requiredRoles: UserRole): Boolean {
        if (!hasRole(call, *requiredRoles)) {
            call.respond(HttpStatusCode.Forbidden, mapOf("error" to "Insufficient permissions"))
            return false
        }
        return true
    }

    /**
     * Require user to be admin
     */
    suspend fun requireAdmin(call: ApplicationCall): Boolean {
        return requireRole(call, UserRole.ADMIN)
    }

    /**
     * Require user to be organizer or admin
     */
    suspend fun requireOrganizerOrAdmin(call: ApplicationCall): Boolean {
        return requireRole(call, UserRole.ORGANIZER, UserRole.ADMIN)
    }

    /**
     * Get principal with null check
     */
    suspend fun getPrincipal(call: ApplicationCall): JWTPrincipal? {
        return call.principal<JWTPrincipal>()
    }
}

package com.example.security

import com.auth0.jwt.JWT
import com.auth0.jwt.algorithms.Algorithm
import com.auth0.jwt.exceptions.JWTVerificationException
import com.example.model.JwtClaims
import com.example.model.UserRole
import java.util.*

class JwtManager(private val secret: String = System.getenv("JWT_SECRET") ?: "your-secret-key-change-this-in-production") {
    private val algorithm = Algorithm.HMAC256(secret)
    private val issuer = "utcn-events-api"
    private val expirationTimeMs = 24 * 60 * 60 * 1000L // 24 hours

    fun generateToken(userId: Long, email: String, role: UserRole): String {
        return JWT.create()
            .withIssuer(issuer)
            .withSubject(userId.toString())
            .withClaim("email", email)
            .withClaim("role", role.name)
            .withExpiresAt(Date(System.currentTimeMillis() + expirationTimeMs))
            .sign(algorithm)
    }

    fun verifyToken(token: String): JwtClaims? {
        return try {
            val decodedJWT = JWT.require(algorithm)
                .withIssuer(issuer)
                .build()
                .verify(token)

            val userId = decodedJWT.subject.toLong()
            val email = decodedJWT.getClaim("email").asString()
            val role = UserRole.valueOf(decodedJWT.getClaim("role").asString())

            JwtClaims(userId, email, role)
        } catch (e: JWTVerificationException) {
            null
        }
    }
}

package com.example.security

import org.mindrot.jbcrypt.BCrypt

object PasswordUtil {
    fun hashPassword(password: String): String {
        return BCrypt.hashpw(password, BCrypt.gensalt(12))
    }

    fun verifyPassword(password: String, hash: String): Boolean {
        return try {
            BCrypt.checkpw(password, hash)
        } catch (e: Exception) {
            false
        }
    }
}

package com.example.service

import com.example.db.dao.UserDao
import com.example.model.*
import com.example.security.JwtManager
import com.example.security.PasswordUtil

class AuthService(
    private val userDao: UserDao,
    private val jwtManager: JwtManager
) {
    fun register(request: UserRegisterRequest): AuthResponse {
        // Check if user already exists
        val existingUser = userDao.findByEmail(request.email)
        if (existingUser != null) {
            throw IllegalArgumentException("User with email ${request.email} already exists")
        }

        // Validate email format
        if (!isValidEmail(request.email)) {
            throw IllegalArgumentException("Invalid email format")
        }

        // Validate password strength
        if (!isValidPassword(request.password)) {
            throw IllegalArgumentException("Password must be at least 8 characters long and contain uppercase, lowercase, digit, and special character")
        }

        // Validate names
        if (request.firstName.isBlank() || request.lastName.isBlank()) {
            throw IllegalArgumentException("First name and last name cannot be empty")
        }

        // Hash password
        val passwordHash = PasswordUtil.hashPassword(request.password)

        // Create user
        val user = User(
            id = 0,
            email = request.email,
            passwordHash = passwordHash,
            firstName = request.firstName,
            lastName = request.lastName,
            role = request.role,
            departmentId = request.departmentId,
            isActive = true
        )

        val createdUser = userDao.create(user)

        // Generate token
        val token = jwtManager.generateToken(createdUser.id, createdUser.email, createdUser.role)

        return AuthResponse(
            token = token,
            user = createdUser.toResponse()
        )
    }

    fun login(request: UserLoginRequest): AuthResponse {
        // Find user by email
        val user = userDao.findByEmail(request.email)
            ?: throw IllegalArgumentException("Invalid email or password")

        // Check if user is active
        if (!user.isActive) {
            throw IllegalArgumentException("User account is inactive")
        }

        // Verify password
        if (!PasswordUtil.verifyPassword(request.password, user.passwordHash)) {
            throw IllegalArgumentException("Invalid email or password")
        }

        // Generate token
        val token = jwtManager.generateToken(user.id, user.email, user.role)

        return AuthResponse(
            token = token,
            user = user.toResponse()
        )
    }

    fun validateToken(token: String): JwtClaims? {
        return jwtManager.verifyToken(token)
    }

    fun getUserById(id: Long): UserResponse? {
        return userDao.findById(id)?.toResponse()
    }

    fun updateUser(id: Long, firstName: String?, lastName: String?, departmentId: Long?): UserResponse? {
        val user = userDao.findById(id) ?: return null

        val updatedUser = user.copy(
            firstName = firstName ?: user.firstName,
            lastName = lastName ?: user.lastName,
            departmentId = departmentId ?: user.departmentId
        )

        return userDao.update(id, updatedUser)?.toResponse()
    }

    fun getUsersByRole(role: UserRole): List<UserResponse> {
        return userDao.findByRole(role).map { it.toResponse() }
    }

    private fun isValidEmail(email: String): Boolean {
        val emailRegex = "^[A-Za-z0-9+_.-]+@(.+)\$".toRegex()
        return emailRegex.matches(email)
    }

    private fun isValidPassword(password: String): Boolean {
        if (password.length < 8) return false
        if (!password.any { it.isUpperCase() }) return false
        if (!password.any { it.isLowerCase() }) return false
        if (!password.any { it.isDigit() }) return false
        if (!password.any { !it.isLetterOrDigit() && it !in listOf('-', '_') }) return false
        return true
    }

    private fun User.toResponse() = UserResponse(
        id = id,
        email = email,
        firstName = firstName,
        lastName = lastName,
        role = role,
        departmentId = departmentId
    )
}

package com.example.service

import com.example.db.dao.RegistrationDao
import com.example.db.dao.EventDao
import com.example.model.Registration
import com.example.model.RegistrationRequest

class RegistrationService(
    private val registrationDao: RegistrationDao,
    private val eventDao: EventDao
) {
    fun registerStudent(studentId: Long, eventId: Long): Registration {
        // Check if student already registered
        val existing = registrationDao.findByStudentAndEvent(studentId, eventId)
        if (existing != null) {
            throw IllegalArgumentException("You are already registered for this event")
        }

        // Check if event exists
        eventDao.findById(eventId)
            ?: throw IllegalArgumentException("Event not found")

        // Create registration
        val registration = Registration(
            id = 0,
            studentId = studentId,
            eventId = eventId,
            status = "REGISTERED"
        )

        return registrationDao.create(registration)
    }

    fun getStudentRegistrations(studentId: Long): List<Registration> {
        return registrationDao.findByStudentId(studentId)
    }

    fun getEventParticipants(eventId: Long): List<Registration> {
        return registrationDao.findByEventId(eventId)
    }

    fun cancelRegistration(studentId: Long, registrationId: Long): Boolean {
        val registration = registrationDao.findById(registrationId)
            ?: throw IllegalArgumentException("Registration not found")

        // Only the student who registered can cancel
        if (registration.studentId != studentId) {
            throw IllegalArgumentException("You can only cancel your own registration")
        }

        // Don't allow cancelling already cancelled registrations
        if (registration.status == "CANCELLED") {
            throw IllegalArgumentException("Registration is already cancelled")
        }

        return registrationDao.updateStatus(registrationId, "CANCELLED")
    }

    fun updateRegistrationStatus(registrationId: Long, status: String, userRole: String): Boolean {
        // Only ADMIN and ORGANIZER can update status
        if (userRole !in listOf("ADMIN", "ORGANIZER")) {
            throw IllegalArgumentException("You don't have permission to update registration status")
        }

        val validStatuses = setOf("REGISTERED", "CANCELLED", "ATTENDED", "NO_SHOW")
        if (status !in validStatuses) {
            throw IllegalArgumentException("Invalid status: $status")
        }

        return registrationDao.updateStatus(registrationId, status)
    }

    fun getRegistrationById(registrationId: Long): Registration? {
        return registrationDao.findById(registrationId)
    }
}

CREATE TABLE IF NOT EXISTS departments (
    id BIGSERIAL PRIMARY KEY,
    name VARCHAR(255) NOT NULL UNIQUE,
    created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE IF NOT EXISTS categories (
    id BIGSERIAL PRIMARY KEY,
    name VARCHAR(255) NOT NULL UNIQUE,
    description TEXT,
    created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TYPE user_role AS ENUM ('STUDENT', 'ORGANIZER', 'ADMIN');

CREATE TABLE IF NOT EXISTS users (
    id BIGSERIAL PRIMARY KEY,
    email VARCHAR(255) NOT NULL UNIQUE,
    password_hash VARCHAR(255) NOT NULL,
    first_name VARCHAR(255) NOT NULL,
    last_name VARCHAR(255) NOT NULL,
    role user_role NOT NULL DEFAULT 'STUDENT',
    department_id BIGINT REFERENCES departments(id),
    is_active BOOLEAN NOT NULL DEFAULT true,
    created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE INDEX idx_users_email ON users(email);
CREATE INDEX idx_users_role ON users(role);
CREATE INDEX idx_users_department ON users(department_id);

-- Update events table to include organizer and category relationship
ALTER TABLE events ADD COLUMN IF NOT EXISTS organizer_id BIGINT REFERENCES users(id);
ALTER TABLE events ADD COLUMN IF NOT EXISTS category_id BIGINT REFERENCES categories(id);
ALTER TABLE events ADD COLUMN IF NOT EXISTS location VARCHAR(255);
ALTER TABLE events ADD COLUMN IF NOT EXISTS start_time TIMESTAMP;
ALTER TABLE events ADD COLUMN IF NOT EXISTS end_time TIMESTAMP;
ALTER TABLE events ADD COLUMN IF NOT EXISTS max_participants INT;
ALTER TABLE events ADD COLUMN IF NOT EXISTS created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP;
ALTER TABLE events ADD COLUMN IF NOT EXISTS updated_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP;

-- Create registrations table
CREATE TABLE IF NOT EXISTS registrations (
    id BIGSERIAL PRIMARY KEY,
    student_id BIGINT NOT NULL REFERENCES users(id),
    event_id BIGINT NOT NULL REFERENCES events(id),
    status VARCHAR(50) NOT NULL DEFAULT 'REGISTERED',
    registered_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
    cancelled_at TIMESTAMP,
    UNIQUE(student_id, event_id)
);

CREATE INDEX idx_registrations_student ON registrations(student_id);
CREATE INDEX idx_registrations_event ON registrations(event_id);
CREATE INDEX idx_registrations_status ON registrations(status);
